import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Testing WebRTC","description":"Notes on Testing WebRTC.","frontmatter":{"title":"Testing WebRTC","description":"Notes on Testing WebRTC."},"headers":[],"relativePath":"software-engineering/webrtc/testing-webrtc.md","filePath":"software-engineering/webrtc/testing-webrtc.md"}'),i={name:"software-engineering/webrtc/testing-webrtc.md"};function n(s,e,l,c,d,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="testing-webrtc" tabindex="-1">Testing WebRTC <a class="header-anchor" href="#testing-webrtc" aria-label="Permalink to &quot;Testing WebRTC&quot;">​</a></h1><p>Interactive sample for testing <strong>trickle ICE</strong> — how WebRTC gathers network candidates through STUN/TURN servers.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://webrtc.github.io/samples/src/content/peerconnection/trickle-ice/" target="_blank" rel="noreferrer">WebRTC samples — Trickle ICE</a></li></ul><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p>The page creates a <code>RTCPeerConnection</code> with configurable ICE servers, starts candidate gathering for a single audio stream, and prints each candidate as it arrives. A completion indicator shows when gathering finishes.</p><h3 id="permissions-note" tabindex="-1">Permissions note <a class="header-anchor" href="#permissions-note" aria-label="Permalink to &quot;Permissions note&quot;">​</a></h3><p>If <code>getUserMedia</code> permission is not persisted for the origin, Chrome may only gather candidates from a <strong>single interface</strong>. Grant microphone/camera permission (or use the page’s permission button) to gather from multiple interfaces. See the <a href="https://datatracker.ietf.org/doc/html/draft-ietf-rtcweb-ip-handling" target="_blank" rel="noreferrer">RTCWEB IP address handling</a> recommendations.</p><h2 id="how-to-interpret-results" tabindex="-1">How to interpret results <a class="header-anchor" href="#how-to-interpret-results" aria-label="Permalink to &quot;How to interpret results&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Candidate <code>type</code></th><th>Meaning</th></tr></thead><tbody><tr><td><code>srflx</code></td><td>STUN reflexive candidate — STUN server works</td></tr><tr><td><code>relay</code></td><td>TURN relay candidate — TURN server works</td></tr></tbody></table><p>Add STUN/TURN URIs with optional username/password. Use the <strong>IceTransports</strong> constraint (<code>all</code> vs <code>relay</code>) to control which candidates are surfaced.</p><p>When testing a single TURN/UDP server, the page can detect <strong>wrong TURN credentials</strong> during authentication.</p><h2 id="typical-workflow" tabindex="-1">Typical workflow <a class="header-anchor" href="#typical-workflow" aria-label="Permalink to &quot;Typical workflow&quot;">​</a></h2><ol><li>Add your STUN and/or TURN server URIs.</li><li>Optionally set TURN username and password.</li><li>Click <strong>Gather candidates</strong>.</li><li>Review the table: time, type, foundation, protocol, address, port, priority, URL, relay protocol.</li><li><code>onicecandidateerror</code> messages are not always fatal (e.g. IPv6 DNS lookup failure while IPv4 relay candidates still work).</li></ol><p><a href="https://webrtc.github.io/samples/src/content/peerconnection/trickle-ice/" target="_blank" rel="noreferrer">Open the live sample →</a></p>',15)])])}const f=t(i,[["render",n]]);export{g as __pageData,f as default};
